// MetricsBuilder provides an interface for scrapers to report metrics while taking care of all the transformations
// required to produce metric representation defined in metadata and user config.
type MetricsBuilder struct {
	config                                     MetricsBuilderConfig // config of the metrics builder.
	startTime                                  pcommon.Timestamp    // start time that will be applied to all recorded data points.
	metricsCapacity                            int                  // maximum observed number of metrics per resource.
	metricsBuffer                              pmetric.Metrics      // accumulates metrics data before emitting.
	buildInfo                                  component.BuildInfo  // contains version information.
	resourceAttributeIncludeFilter             map[string]filter.Filter
	resourceAttributeExcludeFilter             map[string]filter.Filter
	metricAwsNeuronDeviceHostMemoryUsage       metricAwsNeuronDeviceHostMemoryUsage
	metricAwsNeuronDevicePowerUtilization      metricAwsNeuronDevicePowerUtilization
	metricAwsNeuronErrors                      metricAwsNeuronErrors
	metricAwsNeuronExecutionCount              metricAwsNeuronExecutionCount
	metricAwsNeuronExecutionErrors             metricAwsNeuronExecutionErrors
	metricAwsNeuronExecutionLatency            metricAwsNeuronExecutionLatency
	metricAwsNeuronMonitorMemoryUsage          metricAwsNeuronMonitorMemoryUsage
	metricAwsNeuronNeuroncoreDeviceMemoryUsage metricAwsNeuronNeuroncoreDeviceMemoryUsage
	metricAwsNeuronNeuroncoreFlops             metricAwsNeuronNeuroncoreFlops
	metricAwsNeuronNeuroncoreHostMemoryUsage   metricAwsNeuronNeuroncoreHostMemoryUsage
	metricAwsNeuronNeuroncoreInferences        metricAwsNeuronNeuroncoreInferences
	metricAwsNeuronNeuroncoreMemoryUsage       metricAwsNeuronNeuroncoreMemoryUsage
	metricAwsNeuronNeuroncoreStatus            metricAwsNeuronNeuroncoreStatus
	metricAwsNeuronNeuroncoreTimeInUse         metricAwsNeuronNeuroncoreTimeInUse
	metricAwsNeuronNeuroncoreUtilization       metricAwsNeuronNeuroncoreUtilization
	metricAwsNeuronRuntimeMemoryUsage          metricAwsNeuronRuntimeMemoryUsage
	metricAwsNeuronRuntimeVcpuUtilization      metricAwsNeuronRuntimeVcpuUtilization
	metricAwsNeuronSystemCPUUtilization        metricAwsNeuronSystemCPUUtilization
	metricAwsNeuronSystemMemoryUsage           metricAwsNeuronSystemMemoryUsage
}

// MetricBuilderOption applies changes to default metrics builder.
type MetricBuilderOption interface {
	apply(*MetricsBuilder)
}

type metricBuilderOptionFunc func(mb *MetricsBuilder)

func (mbof metricBuilderOptionFunc) apply(mb *MetricsBuilder) {
	mbof(mb)
}

// WithStartTime sets startTime on the metrics builder.
func WithStartTime(startTime pcommon.Timestamp) MetricBuilderOption {
	return metricBuilderOptionFunc(func(mb *MetricsBuilder) {
		mb.startTime = startTime
	})
}
func NewMetricsBuilder(mbc MetricsBuilderConfig, settings receiver.Settings, options ...MetricBuilderOption) *MetricsBuilder {
	mb := &MetricsBuilder{
		config:                                     mbc,
		startTime:                                  pcommon.NewTimestampFromTime(time.Now()),
		metricsBuffer:                              pmetric.NewMetrics(),
		buildInfo:                                  settings.BuildInfo,
		metricAwsNeuronDeviceHostMemoryUsage:       newMetricAwsNeuronDeviceHostMemoryUsage(mbc.Metrics.AwsNeuronDeviceHostMemoryUsage),
		metricAwsNeuronDevicePowerUtilization:      newMetricAwsNeuronDevicePowerUtilization(mbc.Metrics.AwsNeuronDevicePowerUtilization),
		metricAwsNeuronErrors:                      newMetricAwsNeuronErrors(mbc.Metrics.AwsNeuronErrors),
		metricAwsNeuronExecutionCount:              newMetricAwsNeuronExecutionCount(mbc.Metrics.AwsNeuronExecutionCount),
		metricAwsNeuronExecutionErrors:             newMetricAwsNeuronExecutionErrors(mbc.Metrics.AwsNeuronExecutionErrors),
		metricAwsNeuronExecutionLatency:            newMetricAwsNeuronExecutionLatency(mbc.Metrics.AwsNeuronExecutionLatency),
		metricAwsNeuronMonitorMemoryUsage:          newMetricAwsNeuronMonitorMemoryUsage(mbc.Metrics.AwsNeuronMonitorMemoryUsage),
		metricAwsNeuronNeuroncoreDeviceMemoryUsage: newMetricAwsNeuronNeuroncoreDeviceMemoryUsage(mbc.Metrics.AwsNeuronNeuroncoreDeviceMemoryUsage),
		metricAwsNeuronNeuroncoreFlops:             newMetricAwsNeuronNeuroncoreFlops(mbc.Metrics.AwsNeuronNeuroncoreFlops),
		metricAwsNeuronNeuroncoreHostMemoryUsage:   newMetricAwsNeuronNeuroncoreHostMemoryUsage(mbc.Metrics.AwsNeuronNeuroncoreHostMemoryUsage),
		metricAwsNeuronNeuroncoreInferences:        newMetricAwsNeuronNeuroncoreInferences(mbc.Metrics.AwsNeuronNeuroncoreInferences),
		metricAwsNeuronNeuroncoreMemoryUsage:       newMetricAwsNeuronNeuroncoreMemoryUsage(mbc.Metrics.AwsNeuronNeuroncoreMemoryUsage),
		metricAwsNeuronNeuroncoreStatus:            newMetricAwsNeuronNeuroncoreStatus(mbc.Metrics.AwsNeuronNeuroncoreStatus),
		metricAwsNeuronNeuroncoreTimeInUse:         newMetricAwsNeuronNeuroncoreTimeInUse(mbc.Metrics.AwsNeuronNeuroncoreTimeInUse),
		metricAwsNeuronNeuroncoreUtilization:       newMetricAwsNeuronNeuroncoreUtilization(mbc.Metrics.AwsNeuronNeuroncoreUtilization),
		metricAwsNeuronRuntimeMemoryUsage:          newMetricAwsNeuronRuntimeMemoryUsage(mbc.Metrics.AwsNeuronRuntimeMemoryUsage),
		metricAwsNeuronRuntimeVcpuUtilization:      newMetricAwsNeuronRuntimeVcpuUtilization(mbc.Metrics.AwsNeuronRuntimeVcpuUtilization),
		metricAwsNeuronSystemCPUUtilization:        newMetricAwsNeuronSystemCPUUtilization(mbc.Metrics.AwsNeuronSystemCPUUtilization),
		metricAwsNeuronSystemMemoryUsage:           newMetricAwsNeuronSystemMemoryUsage(mbc.Metrics.AwsNeuronSystemMemoryUsage),
		resourceAttributeIncludeFilter:             make(map[string]filter.Filter),
		resourceAttributeExcludeFilter:             make(map[string]filter.Filter),
	}
	if mbc.ResourceAttributes.AwsNeuronDeviceType.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["aws.neuron.device.type"] = filter.CreateFilter(mbc.ResourceAttributes.AwsNeuronDeviceType.MetricsInclude)
	}
	if mbc.ResourceAttributes.AwsNeuronDeviceType.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["aws.neuron.device.type"] = filter.CreateFilter(mbc.ResourceAttributes.AwsNeuronDeviceType.MetricsExclude)
	}
	if mbc.ResourceAttributes.AwsNeuronNeuroncoreVersion.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["aws.neuron.neuroncore.version"] = filter.CreateFilter(mbc.ResourceAttributes.AwsNeuronNeuroncoreVersion.MetricsInclude)
	}
	if mbc.ResourceAttributes.AwsNeuronNeuroncoreVersion.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["aws.neuron.neuroncore.version"] = filter.CreateFilter(mbc.ResourceAttributes.AwsNeuronNeuroncoreVersion.MetricsExclude)
	}
	if mbc.ResourceAttributes.CloudAvailabilityZone.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["cloud.availability_zone"] = filter.CreateFilter(mbc.ResourceAttributes.CloudAvailabilityZone.MetricsInclude)
	}
	if mbc.ResourceAttributes.CloudAvailabilityZone.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["cloud.availability_zone"] = filter.CreateFilter(mbc.ResourceAttributes.CloudAvailabilityZone.MetricsExclude)
	}
	if mbc.ResourceAttributes.CloudProvider.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["cloud.provider"] = filter.CreateFilter(mbc.ResourceAttributes.CloudProvider.MetricsInclude)
	}
	if mbc.ResourceAttributes.CloudProvider.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["cloud.provider"] = filter.CreateFilter(mbc.ResourceAttributes.CloudProvider.MetricsExclude)
	}
	if mbc.ResourceAttributes.CloudRegion.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["cloud.region"] = filter.CreateFilter(mbc.ResourceAttributes.CloudRegion.MetricsInclude)
	}
	if mbc.ResourceAttributes.CloudRegion.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["cloud.region"] = filter.CreateFilter(mbc.ResourceAttributes.CloudRegion.MetricsExclude)
	}
	if mbc.ResourceAttributes.HostID.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["host.id"] = filter.CreateFilter(mbc.ResourceAttributes.HostID.MetricsInclude)
	}
	if mbc.ResourceAttributes.HostID.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["host.id"] = filter.CreateFilter(mbc.ResourceAttributes.HostID.MetricsExclude)
	}
	if mbc.ResourceAttributes.HostType.MetricsInclude != nil {
		mb.resourceAttributeIncludeFilter["host.type"] = filter.CreateFilter(mbc.ResourceAttributes.HostType.MetricsInclude)
	}
	if mbc.ResourceAttributes.HostType.MetricsExclude != nil {
		mb.resourceAttributeExcludeFilter["host.type"] = filter.CreateFilter(mbc.ResourceAttributes.HostType.MetricsExclude)
	}

	for _, op := range options {
		op.apply(mb)
	}
	return mb
}

// NewResourceBuilder returns a new resource builder that should be used to build a resource associated with for the emitted metrics.
func (mb *MetricsBuilder) NewResourceBuilder() *ResourceBuilder {
	return NewResourceBuilder(mb.config.ResourceAttributes)
}

// updateCapacity updates max length of metrics and resource attributes that will be used for the slice capacity.
func (mb *MetricsBuilder) updateCapacity(rm pmetric.ResourceMetrics) {
	if mb.metricsCapacity < rm.ScopeMetrics().At(0).Metrics().Len() {
		mb.metricsCapacity = rm.ScopeMetrics().At(0).Metrics().Len()
	}
}

// ResourceMetricsOption applies changes to provided resource metrics.
type ResourceMetricsOption interface {
	apply(pmetric.ResourceMetrics)
}

type resourceMetricsOptionFunc func(pmetric.ResourceMetrics)

func (rmof resourceMetricsOptionFunc) apply(rm pmetric.ResourceMetrics) {
	rmof(rm)
}

// WithResource sets the provided resource on the emitted ResourceMetrics.
// It's recommended to use ResourceBuilder to create the resource.
func WithResource(res pcommon.Resource) ResourceMetricsOption {
	return resourceMetricsOptionFunc(func(rm pmetric.ResourceMetrics) {
		res.CopyTo(rm.Resource())
	})
}

// WithStartTimeOverride overrides start time for all the resource metrics data points.
// This option should be only used if different start time has to be set on metrics coming from different resources.
func WithStartTimeOverride(start pcommon.Timestamp) ResourceMetricsOption {
	return resourceMetricsOptionFunc(func(rm pmetric.ResourceMetrics) {
		var dps pmetric.NumberDataPointSlice
		metrics := rm.ScopeMetrics().At(0).Metrics()
		for i := 0; i < metrics.Len(); i++ {
			switch metrics.At(i).Type() {
			case pmetric.MetricTypeGauge:
				dps = metrics.At(i).Gauge().DataPoints()
			case pmetric.MetricTypeSum:
				dps = metrics.At(i).Sum().DataPoints()
			}
			for j := 0; j < dps.Len(); j++ {
				dps.At(j).SetStartTimestamp(start)
			}
		}
	})
}

// EmitForResource saves all the generated metrics under a new resource and updates the internal state to be ready for
// recording another set of data points as part of another resource. This function can be helpful when one scraper
// needs to emit metrics from several resources. Otherwise calling this function is not required,
// just `Emit` function can be called instead.
// Resource attributes should be provided as ResourceMetricsOption arguments.
func (mb *MetricsBuilder) EmitForResource(options ...ResourceMetricsOption) {
	rm := pmetric.NewResourceMetrics()
	ils := rm.ScopeMetrics().AppendEmpty()
	ils.Scope().SetName(ScopeName)
	ils.Scope().SetVersion(mb.buildInfo.Version)
	ils.Metrics().EnsureCapacity(mb.metricsCapacity)
	mb.metricAwsNeuronDeviceHostMemoryUsage.emit(ils.Metrics())
	mb.metricAwsNeuronDevicePowerUtilization.emit(ils.Metrics())
	mb.metricAwsNeuronErrors.emit(ils.Metrics())
	mb.metricAwsNeuronExecutionCount.emit(ils.Metrics())
	mb.metricAwsNeuronExecutionErrors.emit(ils.Metrics())
	mb.metricAwsNeuronExecutionLatency.emit(ils.Metrics())
	mb.metricAwsNeuronMonitorMemoryUsage.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreDeviceMemoryUsage.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreFlops.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreHostMemoryUsage.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreInferences.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreMemoryUsage.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreStatus.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreTimeInUse.emit(ils.Metrics())
	mb.metricAwsNeuronNeuroncoreUtilization.emit(ils.Metrics())
	mb.metricAwsNeuronRuntimeMemoryUsage.emit(ils.Metrics())
	mb.metricAwsNeuronRuntimeVcpuUtilization.emit(ils.Metrics())
	mb.metricAwsNeuronSystemCPUUtilization.emit(ils.Metrics())
	mb.metricAwsNeuronSystemMemoryUsage.emit(ils.Metrics())

	for _, op := range options {
		op.apply(rm)
	}
	for attr, filter := range mb.resourceAttributeIncludeFilter {
		if val, ok := rm.Resource().Attributes().Get(attr); ok && !filter.Matches(val.AsString()) {
			return
		}
	}
	for attr, filter := range mb.resourceAttributeExcludeFilter {
		if val, ok := rm.Resource().Attributes().Get(attr); ok && filter.Matches(val.AsString()) {
			return
		}
	}

	if ils.Metrics().Len() > 0 {
		mb.updateCapacity(rm)
		rm.MoveTo(mb.metricsBuffer.ResourceMetrics().AppendEmpty())
	}
}

// Emit returns all the metrics accumulated by the metrics builder and updates the internal state to be ready for
// recording another set of metrics. This function will be responsible for applying all the transformations required to
// produce metric representation defined in metadata and user config, e.g. delta or cumulative.
func (mb *MetricsBuilder) Emit(options ...ResourceMetricsOption) pmetric.Metrics {
	mb.EmitForResource(options...)
	metrics := mb.metricsBuffer
	mb.metricsBuffer = pmetric.NewMetrics()
	return metrics
}

